import 'package:flutter/material.dart';import 'package:flutter_riverpod/flutter_riverpod.dart';import '../../core/utils/app_utils.dart';import '../data/app_repository.dart';class CustomersScreen extends ConsumerWidget{const CustomersScreen({super.key});Future<void> add(BuildContext context,WidgetRef ref)async{final f=GlobalKey<FormState>(),n=TextEditingController(),p=TextEditingController(),l=TextEditingController();final ok=await showDialog<bool>(context:context,builder:(c)=>AlertDialog(title:const Text('Add customer'),content:Form(key:f,child:Column(mainAxisSize:MainAxisSize.min,children:[TextFormField(controller:n,decoration:const InputDecoration(labelText:'Name'),validator:(v)=>Validators.requiredText(v,label:'Name')),const SizedBox(height:10),TextField(controller:p,decoration:const InputDecoration(labelText:'Phone')),const SizedBox(height:10),TextField(controller:l,decoration:const InputDecoration(labelText:'Location'))])),actions:[TextButton(onPressed:()=>Navigator.pop(c),child:const Text('Cancel')),FilledButton(onPressed:(){if(f.currentState!.validate())Navigator.pop(c,true);},child:const Text('Save'))]));if(ok==true)await ref.read(repoProvider).addCustomer(n.text.trim(),p.text.trim(),l.text.trim());}@override Widget build(BuildContext context,WidgetRef ref){final a=ref.watch(customersProvider);return Scaffold(appBar:AppBar(title:const Text('Customers')),body:a.when(loading:()=>const Center(child:CircularProgressIndicator()),error:(e,_)=>Center(child:Text('$e')),data:(x)=>x.isEmpty?const Center(child:Text('No customers yet')):ListView.builder(padding:const EdgeInsets.all(16),itemCount:x.length,itemBuilder:(_,i)=>Card(child:ListTile(leading:CircleAvatar(child:Text(x[i].name[0].toUpperCase())),title:Text(x[i].name,style:const TextStyle(fontWeight:FontWeight.w900)),subtitle:Text([x[i].phone,x[i].location].whereType<String>().join(' · ')))))),floatingActionButton:FloatingActionButton.extended(onPressed:()=>add(context,ref),icon:const Icon(Icons.person_add),label:const Text('Add customer')));}}
